// Build analysis prompt based on system type
const input = $input.first().json;

const { id, name, ip, type, ssh_user, ssh_password } = input;
const lines = input.lines || 100;

const PROXMOX_HOST = '10.1.1.100';
const isLXC = type === 'lxc';
const isDevice = type === 'device';

let log_commands;
if (isLXC) {
  // For LXC: use pct exec via Proxmox
  log_commands = [
    `pct exec ${id} -- journalctl -n ${lines} --no-pager -p warning`,
    `pct exec ${id} -- journalctl -n 50 --no-pager -p err`,
    `pct exec ${id} -- tail -n ${lines} /var/log/syslog 2>/dev/null || true`,
    `pct exec ${id} -- tail -n 20 /var/log/auth.log 2>/dev/null || true`
  ].join(' && echo "---SEPARATOR---" && ');
} else {
  // For VM / physical device: direct SSH
  log_commands = [
    `journalctl -n ${lines} --no-pager -p warning 2>/dev/null || tail -n ${lines} /var/log/syslog 2>/dev/null`,
    `journalctl -n 50 --no-pager -p err 2>/dev/null || true`,
    `tail -n 20 /var/log/auth.log 2>/dev/null || true`,
    `dmesg | tail -n 20 | grep -i -E 'error|fail|warn|crit' 2>/dev/null || true`
  ].join(' && echo "---SEPARATOR---" && ');
}

const connection_info = isLXC
  ? `Connect to Proxmox host ${PROXMOX_HOST} as root and use pct exec commands.`
  : `Connect directly to ${ip} as ${ssh_user}.`;

const prompt = `You are a Linux system administrator analyzing logs for: ${name} (${type}, ${ip || 'N/A'}).

${connection_info}

Execute the following log collection commands:
${log_commands}

Analyze the output and identify:
1. Critical errors (service crashes, kernel panics, OOM kills)
2. Security issues (failed logins, sudo abuse, unauthorized access)
3. Hardware warnings (disk errors, memory failures)
4. Service failures and restarts
5. Network connectivity problems

Respond ONLY with valid JSON in this exact format:
{
  "issues": [
    {
      "severity": "critical|error|warning",
      "message": "<brief description>",
      "timestamp": "<ISO timestamp or 'unknown'>",
      "source": "<log source>"
    }
  ],
  "has_issues": true|false,
  "summary": "<one-line summary of system log health>"
}`;

const system_prompt = 'You are an expert Linux system administrator. Analyze logs and respond ONLY with valid JSON. No markdown, no code blocks, no explanations outside JSON.';

return [{
  json: {
    id, name, ip, type, ssh_user, ssh_password, lines,
    prompt,
    system_prompt,
    is_lxc: isLXC
  }
}];

// Parse Claude's log analysis result
const response = $input.first().json;
const promptData = $('🔧 Build Analysis Prompt').first().json;

let issues = [];
let has_issues = false;
let summary = 'Analysis completed';
let parse_error = null;

try {
  const content = response.choices?.[0]?.message?.content || '{}';
  // Strip markdown code blocks if present
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    issues = parsed.issues || [];
    has_issues = parsed.has_issues || issues.length > 0;
    summary = parsed.summary || 'Log analysis completed';
  }
} catch (e) {
  parse_error = e.message;
  issues = [{ severity: 'error', message: `Log analysis parse error: ${e.message}`, timestamp: new Date().toISOString(), source: 'analyser' }];
  has_issues = true;
}

// Count by severity
const criticalCount = issues.filter(i => i.severity === 'critical').length;
const errorCount = issues.filter(i => i.severity === 'error').length;
const warningCount = issues.filter(i => i.severity === 'warning').length;

return [{
  json: {
    name: promptData.name,
    id: promptData.id,
    type: promptData.type,
    ip: promptData.ip,
    issues,
    has_issues,
    summary,
    counts: {
      critical: criticalCount,
      error: errorCount,
      warning: warningCount,
      total: issues.length
    },
    parse_error,
    analysed_at: new Date().toISOString()
  }
}];
